import numpy as np

def n_step_sarsa_control(env: dict, terminal_states: set, start_state: int, num_states: int, num_actions: int, n: int, alpha: float, gamma: float, epsilon: float, num_episodes: int, seed: int = 42) -> list:
    rng = np.random.RandomState(seed)
    Q = [[0.0] * num_actions for _ in range(num_states)]

    def epsilon_greedy(state):
        if rng.random() < epsilon:
            return int(rng.randint(num_actions))
        q_vals = Q[state]
        max_q = max(q_vals)
        for a in range(num_actions):
            if q_vals[a] == max_q:
                return a

    for _ in range(num_episodes):
        # Circular buffers of length n+1
        S = [None] * (n + 1)
        A = [None] * (n + 1)
        R = [0.0] * (n + 1)

        S[0] = start_state
        A[0] = epsilon_greedy(start_state)
        T = float('inf')
        t = 0

        while True:
            if t < T:
                state = S[t % (n + 1)]
                action = A[t % (n + 1)]

                if (state, action) in env:
                    next_state, reward = env[(state, action)]
                else:
                    next_state, reward = state, 0.0

                R[(t + 1) % (n + 1)] = reward
                S[(t + 1) % (n + 1)] = next_state

                if next_state in terminal_states:
                    T = t + 1
                else:
                    A[(t + 1) % (n + 1)] = epsilon_greedy(next_state)

            tau = t - n + 1
            if tau >= 0:
                G = 0.0
                for i in range(tau + 1, min(tau + n, T) + 1):
                    G += (gamma ** (i - tau - 1)) * R[i % (n + 1)]

                if tau + n < T:
                    G += (gamma ** n) * Q[S[(tau + n) % (n + 1)]][A[(tau + n) % (n + 1)]]

                s_tau = S[tau % (n + 1)]
                a_tau = A[tau % (n + 1)]
                Q[s_tau][a_tau] += alpha * (G - Q[s_tau][a_tau])

            if tau == T - 1:
                break
            t += 1

    return [[round(q, 4) for q in row] for row in Q]

