import numpy as np

def n_step_sarsa_control(env: dict, terminal_states: set, start_state: int, num_states: int, num_actions: int, n: int, alpha: float, gamma: float, epsilon: float, num_episodes: int, seed: int = 42) -> list:
    rng = np.random.RandomState(seed)
    Q = np.zeros((num_states, num_actions), dtype=np.float64)

    # Precompute gamma powers for the n-step return sum
    gamma_powers = gamma ** np.arange(n)  # [1, gamma, gamma^2, ..., gamma^(n-1)]

    def epsilon_greedy(state):
        if rng.random() < epsilon:
            return int(rng.randint(num_actions))
        q_row = Q[state]
        return int(np.argmax(q_row == q_row.max()))  # first max index

    S_buf = np.empty(n + 1, dtype=np.int64)
    A_buf = np.empty(n + 1, dtype=np.int64)
    R_buf = np.zeros(n + 1, dtype=np.float64)

    for _ in range(num_episodes):
        R_buf[:] = 0.0
        S_buf[0] = start_state
        A_buf[0] = epsilon_greedy(start_state)
        T = np.iinfo(np.int64).max
        t = 0

        while True:
            if t < T:
                state = S_buf[t % (n + 1)]
                action = A_buf[t % (n + 1)]

                if (state, action) in env:
                    next_state, reward = env[(state, action)]
                else:
                    next_state, reward = state, 0.0

                R_buf[(t + 1) % (n + 1)] = reward
                S_buf[(t + 1) % (n + 1)] = next_state

                if next_state in terminal_states:
                    T = t + 1
                else:
                    A_buf[(t + 1) % (n + 1)] = epsilon_greedy(next_state)

            tau = t - n + 1
            if tau >= 0:
                end = min(tau + n, T)
                steps = end - tau  # number of reward terms
                # Gather rewards in chronological order from circular buffer
                indices = np.arange(tau + 1, end + 1) % (n + 1)
                G = float(np.dot(gamma_powers[:steps], R_buf[indices]))

                if tau + n < T:
                    G += (gamma ** n) * Q[S_buf[(tau + n) % (n + 1)], A_buf[(tau + n) % (n + 1)]]

                s_tau = S_buf[tau % (n + 1)]
                a_tau = A_buf[tau % (n + 1)]
                Q[s_tau, a_tau] += alpha * (G - Q[s_tau, a_tau])

            if tau == T - 1:
                break
            t += 1

    return [[round(float(q), 4) for q in row] for row in Q]
